 1→import React, { useMemo } from 'react';
 2→import { Layer, Shape } from 'react-konva';
 3→import Nebula from '../components/Nebula';
 4→import { generateDeepSpaceStars, generateNebulae } from '../utils/proceduralGeneration';
 5→
 6→const DeepSpaceLayer = React.memo(({ layerProps }) => {
 7→    const dustStars = useMemo(() => generateDeepSpaceStars(2000, 42), []);
 8→    const nebulae = useMemo(() => generateNebulae(18, 256), []);
 9→
10→    return (
11→        <Layer {...layerProps} listening={false}>
12→            {/* Nebulae (behind dust) */}
13→            {nebulae.map((n, i) => (
14→                <Nebula
15→                    key={i}
16→                    x={n.x}
17→                    y={n.y}
18→                    radius={n.radius}
19→                    opacity={n.opacity}
20→                    color={n.color}
21→                />
22→            ))}
23→            {/* Dust stars — batch-drawn via single Shape for performance */}
24→            <Shape
25→                sceneFunc={(ctx) => {
26→                    ctx.fillStyle = '#ffffff';
27→                    for (let i = 0; i < dustStars.length; i++) {
28→                        const s = dustStars[i];
29→                        ctx.globalAlpha = s.opacity;
30→                        ctx.beginPath();
31→                        ctx.arc(s.x, s.y, s.radius, 0, Math.PI * 2);
32→                        ctx.fill();
33→                    }
34→                    ctx.globalAlpha = 1;
35→                }}
36→                perfectDrawEnabled={false}
37→                listening={false}
38→            />
39→        </Layer>
40→    );
41→});
42→
43→DeepSpaceLayer.displayName = 'DeepSpaceLayer';
44→
45→export default DeepSpaceLayer;
