 1→import React, { useMemo } from 'react';
 2→import { Layer, Shape } from 'react-konva';
 3→import { generateMidGalaxyStars } from '../utils/proceduralGeneration';
 4→import { hexToRgba } from '../utils/starUtils';
 5→
 6→// Pre-parse hex colors to RGB for use in sceneFunc
 7→const parseHex = (hex) => ({
 8→    r: parseInt(hex.slice(1, 3), 16),
 9→    g: parseInt(hex.slice(3, 5), 16),
10→    b: parseInt(hex.slice(5, 7), 16),
11→});
12→
13→const MidGalaxyLayer = React.memo(({ layerProps }) => {
14→    const stars = useMemo(() => {
15→        const raw = generateMidGalaxyStars(800, 137);
16→        // Pre-parse colors for sceneFunc
17→        return raw.map(s => ({ ...s, rgb: parseHex(s.color) }));
18→    }, []);
19→
20→    return (
21→        <Layer {...layerProps} listening={false}>
22→            <Shape
23→                sceneFunc={(ctx) => {
24→                    for (let i = 0; i < stars.length; i++) {
25→                        const s = stars[i];
26→                        const { r, g, b } = s.rgb;
27→                        const grad = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, s.radius);
28→                        grad.addColorStop(0, `rgba(${r},${g},${b},${s.opacity})`);
29→                        grad.addColorStop(1, `rgba(${r},${g},${b},0)`);
30→                        ctx.beginPath();
31→                        ctx.arc(s.x, s.y, s.radius, 0, Math.PI * 2);
32→                        ctx.fillStyle = grad;
33→                        ctx.fill();
34→                    }
35→                }}
36→                perfectDrawEnabled={false}
37→                listening={false}
38→            />
39→        </Layer>
40→    );
41→});
42→
43→MidGalaxyLayer.displayName = 'MidGalaxyLayer';
44→
45→export default MidGalaxyLayer;
