  1→import React, { useMemo } from 'react';
  2→import { Layer, Group, Text, Shape } from 'react-konva';
  3→import StarGroup from '../components/StarGroup';
  4→import { getStarColor, getStarRadius, userHomeCoords } from '../utils/starUtils';
  5→import { generateGalaxyData, drawGalaxyVisuals } from '../utils/galaxyVisuals';
  6→import { computeSemanticBridges } from '../utils/cosmicPhysics';
  7→
  8→const GalaxyLabel = React.memo(({ x, y, name, zoom, onClick }) => {
  9→    const invZoom = 1 / zoom;
 10→    return (
 11→        <Group x={x} y={y} scaleX={invZoom} scaleY={invZoom}>
 12→            <Text
 13→                text={name}
 14→                fontSize={14}
 15→                fill="rgba(255,255,255,0.45)"
 16→                fontStyle="600"
 17→                fontFamily="inherit"
 18→                align="center"
 19→                width={200}
 20→                offsetX={100}
 21→                y={-24}
 22→                perfectDrawEnabled={false}
 23→                onMouseEnter={(e) => {
 24→                    e.target.fill('rgba(255,255,255,0.75)');
 25→                    const container = e.target.getStage().container();
 26→                    container.style.cursor = 'pointer';
 27→                }}
 28→                onMouseLeave={(e) => {
 29→                    e.target.fill('rgba(255,255,255,0.45)');
 30→                    const container = e.target.getStage().container();
 31→                    container.style.cursor = 'grab';
 32→                }}
 33→                onClick={onClick}
 34→                onTap={onClick}
 35→            />
 36→        </Group>
 37→    );
 38→});
 39→
 40→GalaxyLabel.displayName = 'GalaxyLabel';
 41→
 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges
 47→}) => {
 48→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 49→    const galaxyUserIdMap = useMemo(() => {
 50→        const map = new Map();
 51→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 52→        return map;
 53→    }, [galaxies]);
 54→
 55→    // Galaxy spiral visuals — positioned at animated galaxy coords
 56→    const galaxyVisuals = useMemo(() =>
 57→        galaxies?.map(g => ({
 58→            x: g.x,
 59→            y: g.y,
 60→            ...generateGalaxyData(g.userId),
 61→            color: getStarColor(g.userId),
 62→        })) || []
 63→    , [galaxies]);
 64→
 65→    // ── Compute every star's render position ─────────────────────────
 66→    // Stars follow their parent galaxy's displacement from hash→animated,
 67→    // plus an optional pull offset toward similar galaxy centroids.
 68→    const computedStarPositions = useMemo(() => {
 69→        const map = new Map();
 70→        for (const post of posts) {
 71→            const uid = post.users?.id ?? post.user_id;
 72→
 73→            // Galaxy displacement: how far the galaxy moved from hash to animated
 74→            const hashGal = userHomeCoords(uid);
 75→            const animGal = galaxyPositions?.get(uid);
 76→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 77→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 78→
 79→            // Star pull offset (Gravity B)
 80→            const pull = starPullOffsets?.get(post.id);
 81→
 82→            // Base position = original hash+spiral coords
 83→            const baseX = post.universe_x ?? post.display_x;
 84→            const baseY = post.universe_y ?? post.display_y;
 85→
 86→            map.set(post.id, {
 87→                x: baseX + galDx + (pull?.dx ?? 0),
 88→                y: baseY + galDy + (pull?.dy ?? 0),
 89→            });
 90→        }
 91→        return map;
 92→    }, [posts, galaxyPositions, starPullOffsets]);
 93→
 94→    const bridgePairs = useMemo(() => {
 95→        const maxPairs = 120;
 96→
 97→        if (useEmbeddingBridges) {
 98→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
 99→                ? posts.filter((post) => activePostIds.has(post?.id))
100→                : posts;
101→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
102→        }
103→
104→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
105→
106→        return similarPairs
107→            .filter((pair) => Number(pair?.similarity) > 0.9)
108→            .filter((pair) => {
109→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
110→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
111→            })
112→            .slice(0, maxPairs);
113→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
114→
115→    return (
116→        <Layer {...layerProps}>
117→            {/* Semantic bridges between similar posts */}
118→            {bridgePairs.length > 0 && (
119→                <Shape
120→                    sceneFunc={(ctx) => {
121→                        for (const pair of bridgePairs) {
122→                            const posA = computedStarPositions.get(pair.post_a);
123→                            const posB = computedStarPositions.get(pair.post_b);
124→                            if (!posA || !posB) continue;
125→
126→                            const dx = posB.x - posA.x;
127→                            const dy = posB.y - posA.y;
128→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
129→
130→                            const mx = (posA.x + posB.x) / 2;
131→                            const my = (posA.y + posB.y) / 2;
132→                            const perpX = (-dy / dist) * dist * 0.06;
133→                            const perpY = (dx / dist) * dist * 0.06;
134→
135→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
136→                            ctx.lineWidth = 0.8;
137→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
138→                            ctx.shadowBlur = 4;
139→                            ctx.beginPath();
140→                            ctx.moveTo(posA.x, posA.y);
141→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
142→                            ctx.stroke();
143→                        }
144→                        ctx.shadowBlur = 0;
145→                    }}
146→                    perfectDrawEnabled={false}
147→                    listening={false}
148→                />
149→            )}
150→            {/* Spiral galaxy visuals + connection lines */}
151→            <Shape
152→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
153→                perfectDrawEnabled={false}
154→                listening={false}
155→            />
156→            {/* Galaxy name labels */}
157→            {galaxies?.map((g) => (
158→                <GalaxyLabel
159→                    key={g.userId}
160→                    x={g.x}
161→                    y={g.y}
162→                    name={g.name}
163→                    zoom={zoom}
164→                    onClick={() => onGalaxyClick(g)}
165→                />
166→            ))}
167→            {/* Stars */}
168→            {posts.map((post) => {
169→                const postUserId = post.users?.id ?? post.user_id;
170→                const color = getStarColor(postUserId);
171→                const likeCount = post.like_count != null
172→                    ? post.like_count
173→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
174→                const radius = getStarRadius(likeCount);
175→
176→                const pos = computedStarPositions.get(post.id);
177→                const x = pos?.x ?? post.universe_x ?? post.display_x;
178→                const y = pos?.y ?? post.universe_y ?? post.display_y;
179→
180→                return (
181→                    <StarGroup
182→                        key={post.id}
183→                        x={x}
184→                        y={y}
185→                        radius={radius}
186→                        color={color}
187→                        title={post.title}
188→                        showTitle={showTitles}
189→                        isPulsing={pulsingId === post.id}
190→                        onClick={() => onStarClick(post)}
191→                    />
192→                );
193→            })}
194→        </Layer>
195→    );
196→});
197→
198→InteractiveLayer.displayName = 'InteractiveLayer';
199→
200→export default InteractiveLayer;
